    /// Guard: a ticket may not advance further along the state schema than any
    /// of its unresolved `depends_on` targets. Terminal (`done`/`cancelled`)
    /// dependencies are treated as satisfied, cross-store dependencies that are
    /// not locally resolvable are skipped, and cancelling a ticket is always
    /// permitted regardless of dependency progress.
    fn enforce_dependency_progress(
        &self,
        indexed: &IndexedTicket,
        target_state: &str,
    ) -> Result<(), StorageError> {
        if target_state == "cancelled" {
            return Ok(());
        }
        let target_rank =
            self.state_rank_for_type(&indexed.type_id, Some(target_state));
        for edge in self.edges_from(&indexed.id)? {
            if edge.kind != "depends_on" {
                continue;
            }
            let Some(dependency) = self.get_indexed(&edge.to)? else {
                continue;
            };
            let dependency_state = dependency.state.as_deref();
            if matches!(dependency_state, Some("done") | Some("cancelled")) {
                continue;
            }
            let dependency_rank =
                self.state_rank_for_type(&dependency.type_id, dependency_state);
            if target_rank > dependency_rank {
                return Err(StorageError::DependencyNotProgressed {
                    ticket: indexed.id,
                    target_state: target_state.to_string(),
                    dependency: edge.to,
                    dependency_state: dependency_state
                        .unwrap_or("new")
                        .to_string(),
                });
            }
        }
        Ok(())
    }
}

#[derive(Debug)]
struct EdgePatchPlan {

pub fn unclaim(
    &self,
    ticket_id: &Uuid,
) -> Result<(), StorageError> {
    self.index.remove_lease(ticket_id)
}

/// Release the lease on `ticket_id` subject to ownership rules: the holder
/// may always release its own lease, and any caller may release a stale
/// (expired) lease. Releasing a ticket with no active lease is a no-op. A
/// live lease held by a different agent is rejected with `LeaseConflict`.
pub fn release_lease(
    &self,
    ticket_id: &Uuid,
    requester: &str,
) -> Result<(), StorageError> {
    match self.index.get_lease(ticket_id)? {
        None => Ok(()),
        Some(lease) => {
            if lease.working_by == requester || lease.is_expired() {
                self.index.remove_lease(ticket_id)
            } else {
                Err(StorageError::LeaseConflict {
                    ticket: *ticket_id,
                    holder: lease.working_by,
                })
            }
        },
    }
}

pub fn list_leases(&self) -> Result<Vec<LeaseInfo>, StorageError> {
    self.index.list_active_leases()
}

